//! LabTrust deterministic release fixtures and runbook CLI smoke tests.
//!
//! Canonical PCS RC fixtures (`trace.json`, `trace_certificate.json`) are synced from
//! `pcs-core/examples/labtrust-release/` via `make sync-pcs-core-rc`. Negative traces are
//! regenerated by `cargo test -p certifyedge-integration write_fixtures -- --ignored --nocapture`.

use assert_cmd::Command;
use pcs_certificate::{
    is_placeholder_source_commit, is_zero_source_commit, labtrust_gym_root, ZERO_SOURCE_COMMIT,
};

use predicates::prelude::*;

#[path = "../common/support.rs"]
mod support;

use support::{
    assert_certificate_semantics_equal, certifyedge_cmd, env_lock, git_head_commit,
    labtrust_fixture, labtrust_release_certificate_fixture, labtrust_release_fixture,
    pcs_core_rc_manifest_certifyedge_commit, repo_root,
    runbook_labtrust_release_trace, runbook_spec_qc_release, validate_certificate_against_pcs_core,
    validate_labtrust_release_fixture_tree, with_source_commit,
};

const ENV_OVERRIDE_COMMIT: &str = "deadbeefdeadbeefdeadbeefdeadbeefdeadbeef";

fn certifyedge() -> Command {
    certifyedge_cmd()
}

fn emit_release_args(out: &std::path::Path) -> Vec<String> {
    vec![
        "--release-mode".into(),
        "emit-pcs-certificate".into(),
        "--spec".into(),
        runbook_spec_qc_release().to_string_lossy().into_owned(),
        "--trace".into(),
        runbook_labtrust_release_trace()
            .to_string_lossy()
            .into_owned(),
        "--out".into(),
        out.to_string_lossy().into_owned(),
    ]
}

/// Exact runbook: check-trace → emit-pcs-certificate → verify-certificate --trace
#[test]
fn test_cli_labtrust_release_runbook_smoke() {
    let trace = runbook_labtrust_release_trace();
    let spec = runbook_spec_qc_release();
    let cert_out = repo_root().join("target/trace_certificate.json");

    certifyedge()
        .args([
            "check-trace",
            "--spec",
            spec.to_str().unwrap(),
            "--trace",
            trace.to_str().unwrap(),
        ])
        .assert()
        .success()
        .stdout(predicate::str::contains("PASS"));

    with_source_commit(&pcs_core_rc_manifest_certifyedge_commit(), || {
        certifyedge()
            .args(emit_release_args(&cert_out))
            .assert()
            .success()
            .stdout(predicate::str::contains("source_commit_resolution=env"))
            .stdout(predicate::str::contains("CertificateChecked"));
    });

    validate_certificate_against_pcs_core(&cert_out);

    certifyedge()
        .args([
            "verify-certificate",
            cert_out.to_str().unwrap(),
            "--trace",
            trace.to_str().unwrap(),
        ])
        .assert()
        .success();
}

