fn test_labtrust_release_fixture_tree_validates() {
    validate_labtrust_release_fixture_tree();
}

#[test]
fn test_labtrust_release_trace_matches_labtrust_gym_export() {
    let release: serde_json::Value =
        serde_json::from_str(
            &std::fs::read_to_string(labtrust_release_fixture("trace.json")).unwrap(),
        )
            .unwrap();
    let gym: serde_json::Value = serde_json::from_str(
        &std::fs::read_to_string(labtrust_fixture("valid_trace.json")).unwrap(),
    )
    .unwrap();
    assert_eq!(
        release["trace_hash"], gym["trace_hash"],
        "labtrust-release trace must match tests/labtrust/valid_trace.json (LabTrust-Gym export)"
    );
}

#[test]
fn test_labtrust_release_certificate_fixture_is_cli_generated() {
    let fixture = labtrust_release_certificate_fixture();
    let fixture_value: serde_json::Value =
        serde_json::from_str(&std::fs::read_to_string(&fixture).unwrap()).unwrap();
    assert_eq!(
        fixture_value["source_commit"].as_str().unwrap(),
        pcs_core_rc_manifest_certifyedge_commit()
    );

    certifyedge()
        .args([
            "verify-certificate",
            fixture.to_str().unwrap(),
            "--trace",
            labtrust_release_fixture("trace.json").to_str().unwrap(),
        ])
        .assert()
        .success();

    let out = repo_root().join("target/labtrust_release_reemit.json");
    with_source_commit(&pcs_core_rc_manifest_certifyedge_commit(), || {
        certifyedge()
            .args(emit_release_args(&out))
            .assert()
            .success();
    });

    let emitted: serde_json::Value =
        serde_json::from_str(&std::fs::read_to_string(&out).unwrap()).unwrap();
    assert_certificate_semantics_equal(&emitted, &fixture_value);
}

