#[test]
fn test_trace_certificate_source_commit_is_not_placeholder() {
    let cert: serde_json::Value = serde_json::from_str(
        &std::fs::read_to_string(labtrust_release_certificate_fixture()).unwrap(),
    )
    .unwrap();
    let commit = cert["source_commit"].as_str().unwrap();
    assert!(!is_placeholder_source_commit(commit));
    assert!(!is_zero_source_commit(commit));
    assert_eq!(commit, pcs_core_rc_manifest_certifyedge_commit().as_str());
}

fn git_head_commit_in(root: &std::path::Path) -> Option<String> {
    let output = std::process::Command::new("git")
        .args(["-C", root.to_str()?, "rev-parse", "HEAD"])
        .output()
        .ok()?;
    if !output.status.success() {
        return None;
    }
    let commit = String::from_utf8_lossy(&output.stdout).trim().to_string();
    (commit.len() >= 7).then_some(commit)
}

fn assert_check_trace_counterexample(trace_file: &str, fixture_cx_file: &str, reason: &str) {
    let spec = runbook_spec_qc_release();
    let out_cx = repo_root()
        .join("target")
        .join(format!("cx_check_{trace_file}"));

    certifyedge()
        .args([
            "check-trace",
            "--spec",
            spec.to_str().unwrap(),
            "--trace",
            labtrust_release_fixture(trace_file).to_str().unwrap(),
            "--counterexample-out",
            out_cx.to_str().unwrap(),
        ])
        .assert()
        .failure();

    let expected: serde_json::Value = serde_json::from_str(
        &std::fs::read_to_string(labtrust_release_fixture(fixture_cx_file)).unwrap(),
    )
    .unwrap();
    let actual: serde_json::Value =
        serde_json::from_str(&std::fs::read_to_string(&out_cx).unwrap()).unwrap();
    assert_eq!(expected["reason"], reason);
    assert_eq!(actual["reason"], reason);
    assert_eq!(actual["property_id"], expected["property_id"]);
    assert!(actual["counterexample_id"].is_string());
    assert!(actual["violating_event_id"].is_string());
}
